/**
 * @brief Show focus on a specific item (index relative to current page)
 *
 * @param index Item index on current page (0 to items_per_page-1)
 */
static void ui_floder_screen_keyboard_focus_show(uint32_t index)
{
    lv_obj_t *last_focus_obj = NULL;
    lv_obj_t *focus_obj = NULL;
    ui_fs_file_node_t *node = NULL;

    // Calculate items on current page
    uint32_t start_index = __current_page * __items_per_page;
    uint32_t end_index = start_index + __items_per_page;
    if (end_index > __focus_obj_count) {
        end_index = __focus_obj_count;
    }
    uint32_t items_on_current_page = end_index - start_index;

    // Validate index
    if (index >= items_on_current_page) {
        return;
    }

    // Get last focus object (using current page-relative index)
    uint32_t last_global_index = start_index + __focus_obj_current_index;
    if (last_global_index < __focus_obj_count) {
        node = ui_fs_file_list_get_node_by_index(sg_file_list, last_global_index);
        if (node != NULL) {
            last_focus_obj = (lv_obj_t *)node->user_data;
        }
    }

    // Get new focus object (convert page-relative index to global index)
    uint32_t global_index = start_index + index;
    node = ui_fs_file_list_get_node_by_index(sg_file_list, global_index);
    if (node == NULL) {
        return;
    }

    focus_obj = (lv_obj_t *)node->user_data;
    if (NULL == focus_obj) {
        return;
    }

    // Defocus last focus object
    if (NULL != last_focus_obj) {
        lv_obj_send_event(last_focus_obj, LV_EVENT_DEFOCUSED, NULL);
        // LV_LOG_USER("defocus last focus object: %p (global index: %d)", last_focus_obj, last_global_index);
    }

    // Focus new focus object (store page-relative index)
    __focus_obj_current_index = index;
    lv_obj_send_event(focus_obj, LV_EVENT_FOCUSED, NULL);
    // LV_LOG_USER("focus new focus object: %p (page: %d, page index: %d, global index: %d)",
    //             focus_obj, __current_page, index, global_index);
}

/**
 * @brief Move focus to previous item with pagination support
 *
 * For e-paper display, when moving to previous page, refresh the display
 * to show the new page content. Stops at the first item (no wrap around).
 */
static void ui_floder_screen_keyboard_focus_prev(void)
{
    // Check if folder is empty
    if (__focus_obj_count == 0) {
        LV_LOG_USER("Empty folder, cannot move focus");
        return;
    }

    int32_t index = __focus_obj_current_index - 1;

    // Check if we need to go to previous page
    if (index < 0) {
        if (__current_page == 0) {
            // At first page and first item, do nothing (stop here)
            LV_LOG_USER("Already at first item, cannot go previous");
            return;
        } else {
            // Go to previous page, focus on last item
            __current_page--;
            ui_floder_screen_file_list_render_page(__current_page);

            // Calculate items on the new current page
            uint32_t start_index = __current_page * __items_per_page;
            uint32_t end_index = start_index + __items_per_page;
            if (end_index > __focus_obj_count) {
                end_index = __focus_obj_count;
            }
            uint32_t items_on_page = end_index - start_index;

            // Focus on last item of previous page
            index = items_on_page - 1;
        }
    }

    ui_floder_screen_keyboard_focus_show(index);
}

/**
 * @brief Move focus to next item with pagination support
 *
 * For e-paper display, when moving to next page, refresh the display
 * to show the new page content. Stops at the last item (no wrap around).
 */
static void ui_floder_screen_keyboard_focus_next(void)
{
    // Check if folder is empty
    if (__focus_obj_count == 0) {
        LV_LOG_USER("Empty folder, cannot move focus");
        return;
    }

    // Calculate items on current page
    uint32_t start_index = __current_page * __items_per_page;
    uint32_t end_index = start_index + __items_per_page;
    if (end_index > __focus_obj_count) {
        end_index = __focus_obj_count;
    }
    int32_t items_on_current_page = (int32_t)(end_index - start_index);

    int32_t index = __focus_obj_current_index + 1;

    // Check if we need to go to next page
    if (index >= items_on_current_page) {
        // Move to next page
        if (__current_page < __total_pages - 1) {
            // Go to next page
            __current_page++;
            ui_floder_screen_file_list_render_page(__current_page);
            index = 0;
        } else {
            // At last page and last item, do nothing (stop here)
            LV_LOG_USER("Already at last item, cannot go next");
            return;
        }
    }

    ui_floder_screen_keyboard_focus_show(index);
}

static void ui_floder_screen_keyboard_enter(void)
{
    // Check if folder is empty
    if (__focus_obj_count == 0) {
        LV_LOG_USER("Empty folder, cannot enter");
        return;
    }

    // Calculate global index from current page and page-relative index
    uint32_t global_index = __current_page * __items_per_page + __focus_obj_current_index;

    if (global_index >= __focus_obj_count) {
        return;
    }

    // get focus object
    ui_fs_file_node_t *node = ui_fs_file_list_get_node_by_index(sg_file_list, global_index);
    if (NULL == node) {
        return;
    }
    lv_obj_t *focus_obj = (lv_obj_t *)node->user_data;
    if (NULL == focus_obj) {
        return;
    }

    // Only enter directories, not files
    if (node->type != UI_FS_FILE_TYPE_DIRECTORY) {
        /* Open file in file screen */
        char full_path[512];
        size_t path_len = strlen(sg_current_path);

        int need_slash = 0;
        if (path_len > 0 && sg_current_path[path_len - 1] != '/') {
            need_slash = 1;
        }

        snprintf(full_path, sizeof(full_path), "%s%s%s", sg_current_path,
                 need_slash ? "/" : "", node->name);

        /* Remove TF_CARD_ROOT_PATH prefix if present */
        const char *relative_path = full_path;
        if (strncmp(full_path, TF_CARD_ROOT_PATH, strlen(TF_CARD_ROOT_PATH)) == 0) {
            relative_path = full_path + strlen(TF_CARD_ROOT_PATH);
            if (*relative_path == '/') {
                relative_path++;
            }
        }

        ui_file_screen_open_file(relative_path, node->type);
        LV_LOG_USER("Opening file: %s (type: %d)", relative_path, node->type);
        return;
    }

    // get path
    size_t path_len = strlen(sg_current_path);
    size_t name_len = strlen(node->name);

    // 检查路径末尾是否带有'/'
    int need_slash = 0;
    if (path_len > 0 && sg_current_path[path_len - 1] != '/') {
        need_slash = 1;
    }

    // 计算新路径所需的总长度（包括 '\0'）
    size_t total_len = path_len + need_slash + name_len + 1;

    // 比较所需长度与当前分配的大小
    if (total_len > sg_current_path_size) {
        // 需要重新分配更大的内存
        size_t new_size = ((total_len - 1) / UI_FLODER_PATH_MALLOC_ALIGN_SIZE + 1) * UI_FLODER_PATH_MALLOC_ALIGN_SIZE;
        char *new_path = lv_malloc(new_size);
        if (NULL == new_path) {
            LV_LOG_ERROR("ui_floder_screen_keyboard_enter: failed to allocate memory");
            return;
        }
        memset(new_path, 0, new_size);

        // 拷贝原路径
        strncpy(new_path, sg_current_path, new_size - 1);

        // 释放旧内存
        lv_free(sg_current_path);
        sg_current_path = new_path;
        sg_current_path_size = new_size;

        // 更新 path_len（虽然应该不变，但为了安全）
        path_len = strlen(sg_current_path);
    }

    size_t offset = path_len;
    if (need_slash) {
        if (offset + 1 < sg_current_path_size) {
            sg_current_path[offset] = '/';
            offset += 1;
        }
    }

    // 拷贝文件名，确保不超过剩余空间
    size_t remaining = sg_current_path_size - offset;
    if (remaining > 0) {
        strncpy(sg_current_path + offset, node->name, remaining - 1);
        sg_current_path[sg_current_path_size - 1] = '\0';  // 确保字符串终止
    }

    // push focus object global index to stack
    if (__focus_obj_stack_index < __FOCUS_OBJ_STACK_MAX_COUNT) {
        __focus_obj_stack[__focus_obj_stack_index] = global_index;
    }
    __focus_obj_stack_index++;

    // show file list (this will reset to page 0)
    ui_floder_screen_file_list_show(sg_current_path);

    // show focus object (start at first item of first page, only if not empty)
    if (__focus_obj_count > 0) {
        ui_floder_screen_keyboard_focus_show(0);
    }

    return;
}

static void ui_floder_screen_keyboard_esc(void)
{
    if (NULL == sg_current_path) {
        return;
    }

    // 如果当前路径是根目录，则返回主界面
    if (__focus_obj_stack_index == 0) {
        _ui_screen_change(&ui_home_screen, LV_SCR_LOAD_ANIM_FADE_ON, 0, 0, &ui_home_screen_screen_init);
        return;
    }

    // 返回上一级界面， 分隔符 '/'
    size_t path_len = strlen(sg_current_path);
    for (size_t i = path_len - 1; i > 0; i--) {
        if (sg_current_path[i] == '/') {
            sg_current_path[i] = '\0';
            break;
        }
    }

    // pop focus object global index from stack
    uint32_t saved_global_index = 0;
    if (__focus_obj_stack_index > 0) {
        __focus_obj_stack_index--;
    }

    if (__focus_obj_stack_index < __FOCUS_OBJ_STACK_MAX_COUNT) {
        saved_global_index = __focus_obj_stack[__focus_obj_stack_index];
    }

    // show file list (this will reset to page 0)
    ui_floder_screen_file_list_show(sg_current_path);

    // Calculate which page the saved item is on
    __current_page = saved_global_index / __items_per_page;
    if (__current_page >= __total_pages) {
        __current_page = __total_pages > 0 ? __total_pages - 1 : 0;
    }

    // Render the page containing the previously focused item
    ui_floder_screen_file_list_render_page(__current_page);

    // Calculate page-relative index
    uint32_t page_relative_index = saved_global_index - (__current_page * __items_per_page);

    // Validate page-relative index
    uint32_t start_index = __current_page * __items_per_page;
    uint32_t end_index = start_index + __items_per_page;
    if (end_index > __focus_obj_count) {
        end_index = __focus_obj_count;
    }
    uint32_t items_on_page = end_index - start_index;

    if (page_relative_index >= items_on_page) {
        page_relative_index = 0;
    }

    // show focus object (only if folder is not empty)
    if (__focus_obj_count > 0) {
        ui_floder_screen_keyboard_focus_show(page_relative_index);
    }

    return;
}

static void ui_floder_screen_keyboard_handler(lv_event_t * e)
{
    lv_key_t key = lv_event_get_key(e);

    switch (key) {
        case LV_KEY_UP:
        case LV_KEY_LEFT:
            ui_floder_screen_keyboard_focus_prev();
            LV_LOG_USER("ui_floder_screen_keyboard_handler: UP or LEFT");
            break;
        case LV_KEY_PREV:
            break;
        case LV_KEY_DOWN:
        case LV_KEY_RIGHT:
            ui_floder_screen_keyboard_focus_next();
            LV_LOG_USER("ui_floder_screen_keyboard_handler: DOWN or RIGHT");
            break;
        case LV_KEY_NEXT:
            break;
        case LV_KEY_ENTER:
            ui_floder_screen_keyboard_enter();
            LV_LOG_USER("ui_floder_screen_keyboard_handler: ENTER");
            break;
        case LV_KEY_ESC:
            ui_floder_screen_keyboard_esc();
            LV_LOG_USER("ui_floder_screen_keyboard_handler: ESC");
            break;
        default:
            break;
    }
}

