/**
 * @brief Calculate how many items can fit per page dynamically
 *
 * This function calculates based on:
 * 1. Container height (ui_floder_screen_list_container)
 * 2. Item height (by creating a temporary item to measure)
 * 3. Flex layout gap/spacing
 *
 * @return Number of items that can fit on one page
 */
static uint32_t ui_floder_screen_calculate_items_per_page(void)
{
    if (!ui_floder_screen_list_container) {
        return 6;  // Default fallback value
    }

    // Ensure layout is updated before measuring
    lv_obj_update_layout(ui_floder_screen_list_container);

    // Get container height
    int32_t container_height = lv_obj_get_height(ui_floder_screen_list_container);

    // Create a temporary item to measure its height
    lv_obj_t *temp_item = ui_floder_item_container_create(ui_floder_screen_list_container);
    if (!temp_item) {
        return 6;  // Default fallback value
    }

    // Set a sample icon and label to get realistic height
    lv_image_set_src(ui_comp_get_child(temp_item, UI_COMP_FLODER_ITEM_CONTAINER_ICON),
                     &ui_img_image_floder_floder_32_png);
    lv_label_set_text(ui_comp_get_child(temp_item, UI_COMP_FLODER_ITEM_CONTAINER_LABEL),
                      "Sample");

    // Force layout update to get accurate measurements
    lv_obj_update_layout(temp_item);

    // Get item height (including padding)
    int32_t item_height = lv_obj_get_height(temp_item);

    // Get flex gap (spacing between items)
    int32_t flex_gap = lv_obj_get_style_pad_row(ui_floder_screen_list_container, LV_PART_MAIN);

    // Delete temporary item
    lv_obj_delete(temp_item);

    // Calculate items per page
    // Add flex_gap to item_height to account for spacing between items
    int32_t effective_item_height = item_height + flex_gap;

    uint32_t items_per_page = 1;  // At least 1 item
    if (effective_item_height > 0) {
        items_per_page = container_height / effective_item_height;
    }

    // Ensure at least 1 item per page, but reasonable maximum
    if (items_per_page < 1) {
        items_per_page = 1;
    } else if (items_per_page > 20) {
        // Sanity check: probably something wrong with measurement
        items_per_page = 6;  // Use default
    }

    LV_LOG_USER("Calculated items per page: %d (container: %d, item: %d, gap: %d)",
                items_per_page, container_height, item_height, flex_gap);

    return items_per_page;
}

static void ui_floder_screen_list_container_clear(void)
{
    if (!ui_floder_screen_list_container) {
        return;
    }
    lv_obj_clean(ui_floder_screen_list_container);
}

static const void *ui_floder_screen_file_list_get_icon(ui_fs_file_type_t type)
{
    switch (type) {
        case UI_FS_FILE_TYPE_DIRECTORY:
            return &ui_img_image_floder_floder_32_png;
        case UI_FS_FILE_TYPE_FILE_PNG:
            return &ui_img_image_floder_png_32_png;
        case UI_FS_FILE_TYPE_FILE_TEXT:
            return &ui_img_image_floder_txt_32_png;
        case UI_FS_FILE_TYPE_FILE_EPUB:
            return &ui_img_image_floder_epub_32_png;
        default:
            return &ui_img_image_floder_unkonwn_32_png;
    }
}

/**
 * @brief Render a specific page of the file list
 *
 * This function clears the container and displays only the items
 * for the specified page. Designed for e-paper displays to minimize
 * unnecessary redraws.
 *
 * @param page Page index to render (0-based)
 */
static void ui_floder_screen_file_list_render_page(uint32_t page)
{
    // Clear container first
    ui_floder_screen_list_container_clear();

    if (sg_file_list == NULL || sg_file_list->node_count == 0) {
        // Empty folder, just clear and return
        return;
    }

    // Validate page number
    if (page >= __total_pages) {
        page = __total_pages - 1;
    }

    // Calculate which items to display
    uint32_t start_index = page * __items_per_page;
    uint32_t end_index = start_index + __items_per_page;
    if (end_index > sg_file_list->node_count) {
        end_index = sg_file_list->node_count;
    }

    // Clear all user_data pointers first (UI objects will be deleted)
    ui_fs_file_node_t *node = sg_file_list->head;
    while (node != NULL) {
        node->user_data = NULL;
        node = (ui_fs_file_node_t *)node->next;
    }

    // Skip to start_index
    node = sg_file_list->head;
    for (uint32_t i = 0; i < start_index && node != NULL; i++) {
        node = (ui_fs_file_node_t *)node->next;
    }

    // Create UI items for current page
    for (uint32_t i = start_index; i < end_index && node != NULL; i++) {
        lv_obj_t *item = ui_floder_item_container_create(ui_floder_screen_list_container);
        lv_obj_set_x(item, 0);
        lv_obj_set_y(item, 0);

        // set icon
        const void *icon = ui_floder_screen_file_list_get_icon(node->type);
        lv_image_set_src(ui_comp_get_child(item, UI_COMP_FLODER_ITEM_CONTAINER_ICON), icon);

        // set label
        lv_label_set_text(ui_comp_get_child(item, UI_COMP_FLODER_ITEM_CONTAINER_LABEL), node->name);

        // set user data (link node to UI object)
        node->user_data = item;

        node = (ui_fs_file_node_t *)node->next;
    }

    // Update page info in status bar (optional - can show "Page 1/3")
    // LV_LOG_USER("Rendered page %d/%d (items %d-%d)", page + 1, __total_pages, start_index, end_index - 1);
}

/**
 * @brief Load file list from path and display first page
 *
 * @param path Directory path to list
 */
static void ui_floder_screen_file_list_show(const char *path)
{
    if (NULL == path) {
        return;
    }

    if (NULL != sg_file_list) {
        ui_fs_file_list_destroy(sg_file_list);
        sg_file_list = NULL;
    }

    int ui_rt = ui_fs_get_file_list(path, &sg_file_list);
    if (ui_rt != 0 || sg_file_list == NULL) {
        // No files found, reset pagination
        __focus_obj_count = 0;
        __current_page = 0;
        __total_pages = 0;
        ui_floder_screen_list_container_clear();
        return;
    }

    ui_fs_file_list_sort(sg_file_list);

    // Calculate items per page dynamically (only if not already calculated or container changed)
    if (__items_per_page == 0) {
        __items_per_page = ui_floder_screen_calculate_items_per_page();
    }

    // Update pagination info
    __focus_obj_count = sg_file_list->node_count;

    // Handle empty folder case
    if (__focus_obj_count == 0) {
        __total_pages = 0;
        __current_page = 0;
        __focus_obj_current_index = -1;  // No valid focus
        ui_floder_screen_file_list_render_page(0);  // Will show "Empty Folder" message
        LV_LOG_USER("Empty folder, no items to display");
        return;
    }

    // Calculate total pages for non-empty folder
    __total_pages = (__focus_obj_count + __items_per_page - 1) / __items_per_page;  // Ceiling division
    if (__total_pages == 0) {
        __total_pages = 1;
    }
    __current_page = 0;  // Start from first page

    // Render first page
    ui_floder_screen_file_list_render_page(__current_page);

    return;
}

